insert into public.words (id, chapter_id, word, clue, expert_clue, verse, scripture, summary, sort_order) values
  ('daniel-three-1', 'daniel-three', 'IMAGE OF GOLD', 'Nebuchadnezzar''s idol on the plain of Dura that all were commanded to worship.', null, 'Daniel 3:1', 'apter 3 Nebuchadnezzar the king made an image of gold, whose height was threescore cubits, and the breadth thereof six cubits: he set it up in the plain of Dura, in the province of Babylon. 2Then Nebuchadnezzar the king sent to gather together the princes, the', 'Earthly power demands worship; God''s people must obey Him rather than human decrees.', 0),
  ('daniel-three-2', 'daniel-three', 'FALL DOWN AND WORSHIP', 'The command at the sound of music when the golden image was dedicated.', null, 'Daniel 3:5', ', dulcimer, and all kinds of musick, ye fall down and worship the golden image that Nebuchadnezzar the king hath set up: 6And whoso falleth not down and worshippeth shall the same hour be cast into the midst of a burning fiery furnace. 7Therefore at that time,', 'The test of worship is not private opinion but public allegiance when music sounds and crowds bow.', 1),
  ('daniel-three-3', 'daniel-three', 'FURNACE HEATED SEVENFOLD', 'Nebuchadnezzar''s rage turned the execution fire hotter than usual.', null, 'Daniel 3:19', 'd that they should heat the furnace one seven times more than it was wont to be heated. 20And he commanded the most mighty men that were in his army to bind Shadrach, Meshach, and Abed-nego, and to cast them into the burning fiery furnace. 21Then these men wer', 'Opposition to truth often intensifies when faithful witnesses refuse to compromise.', 2),
  ('daniel-three-4', 'daniel-three', 'FOURTH MAN LOOSE', 'The king saw one like the Son of God walking with the three in the fire.', null, 'Daniel 3:25', 'no hurt; and the form of the fourth is like the Son of God. 26Then Nebuchadnezzar came near to the mouth of the burning fiery furnace, and spake, and said, Shadrach, Meshach, and Abed-nego, ye servants of the most high God, come forth, and come hither. Then S', 'Christ walks with believers in their fiercest trials, preserving them for His glory.', 3),
  ('daniel-three-5', 'daniel-three', 'NO HURT UPON BODIES', 'After the furnace, not a hair was singed nor the smell of fire passed on them.', null, 'Daniel 3:27', 'pon whose bodies the fire had no power, nor was an hair of their head singed, neither were their coats changed, nor the smell of fire had passed on them. 28Then Nebuchadnezzar spake, and said, Blessed be the God of Shadrach, Meshach, and Abed-nego, who hath se', 'Complete deliverance demonstrates that faith in God is safer than obedience to tyranny.', 4),
  ('daniel-five-1', 'daniel-five', 'GOLDEN VESSELS', 'Temple articles profaned at Babylon''s drunken feast.', null, 'Daniel 5:2', 't drink therein. 3Then they brought the golden vessels that were taken out of the temple of the house of God which was at Jerusalem; and the king, and his princes, his wives, and his concubines, drank in them. 4They drank wine, and praised the gods of gold, an', 'Desecrating what is holy hastens judgment on those who mock God openly.', 0),
  ('daniel-five-2', 'daniel-five', 'FINGERS OF A MANS HAND', 'The part of the hand that wrote on the palace plaster.', null, 'Daniel 5:5', 'of stone. 5In the same hour came forth fingers of a man''s hand, and wrote over against the candlestick upon the plaister of the wall of the king''s palace: and the king saw the part of the hand that wrote. 6Then the king''s countenance was changed, and his thou', 'God interrupts human revelry with warnings the proud cannot ignore.', 1),
  ('daniel-five-3', 'daniel-five', 'MENE MENE TEKEL UPHARSIN', 'The four words Daniel interpreted before Belshazzar.', null, 'Daniel 5:25', 'd this is the writing that was written, MENE, MENE, TEKEL, UPHARSIN. 26This is the interpretation of the thing: MENE; God hath numbered thy kingdom, and finished it. 27TEKEL; Thou art weighed in the balances, and art found wanting. 28PERES; Thy kingdom is divi', 'Heaven weighs character and measures kingdoms; every soul is numbered before God.', 2),
  ('daniel-five-4', 'daniel-five', 'TEKEL THOU ART WEIGHED', 'Daniel told the king he was found wanting in the balances.', null, 'Daniel 5:27', 'umbered thy kingdom, and finished it. 27TEKEL; Thou art weighed in the balances, and art found wanting. 28PERES; Thy kingdom is divided, and given to the Medes and Persians. 1651 Daniel 5', 'No earthly throne exempts a life from God''s moral evaluation.', 3),
  ('daniel-five-5', 'daniel-five', 'THAT NIGHT BELSHAZZAR', 'The king of the Chaldeans was slain when the sentence fell.', null, 'Daniel 5:30', 'ld be the third ruler in the kingdom. 30In that night was Belshazzar the king of the Chaldeans slain. 31And Darius the Median took the kingdom, being about threescore and two years old. 1652 Daniel 5', 'Probation closes suddenly for those who persist in defiance after clear warning.', 4),
  ('daniel-six-1', 'daniel-six', 'LAW OF MEDES AND PERSIANS', 'A decree that could not be altered once signed by the king.', null, 'Daniel 6:8', 'hat it be not changed, according to the law of the Medes and Persians, which altereth not. 9Wherefore king Darius signed the writing and the decree. 10Now when Daniel knew that the writing was signed, he went into his house; and his windows being open in his c', 'Human laws may be rigid, but God''s servants answer first to a higher court.', 0),
  ('daniel-six-2', 'daniel-six', 'THRICE DAILY UPON KNEES', 'Daniel''s open window prayer toward Jerusalem.', null, 'Daniel 6:10', 'g open in his chamber toward Jerusalem, he kneeled upon his knees three times a day, and prayed, and gave thanks before his God, as he did aforetime. 11Then these men assembled, and found Daniel praying and making supplication before his God. 12Then they came', 'Faithful prayer habits prepare the soul to stand when persecution comes.', 1),
  ('daniel-six-3', 'daniel-six', 'DEN OF LIONS', 'The pit where Daniel was cast for praying to his God.', null, 'Daniel 6:16', 'commanded, and they brought Daniel, and cast him into the den of lions. Now the king spake and said unto Daniel, Thy God whom thou servest continually, he will deliver thee. 17And a stone was brought and laid upon the mouth of the den; and the king sealed it w', 'The same place meant for destruction became a testimony of divine protection.', 2),
  ('daniel-six-4', 'daniel-six', 'GOD HATH SENT HIS ANGEL', 'Daniel''s explanation for why the lions did not hurt him.', null, 'Daniel 6:22', 'o the king, O king, live for ever. 22My God hath sent his angel, and hath shut the lions mouths, that they have not hurt me: forasmuch as before him innocency was found in me; and also before thee, O king, have I done no hurt. 23Then was the king exceeding gla', 'Angels minister to those who serve God with an upright heart before Him.', 3),
  ('daniel-six-5', 'daniel-six', 'LIVING GOD FOREVER', 'Darius decreed that Daniel''s God is the living God whose kingdom shall not be destroyed.', null, 'Daniel 6:26', 'and fear before the God of Daniel: for he is the living God, and stedfast for ever, and his kingdom that which shall not be destroyed, and his dominion shall be even unto the end. 27He delivereth and rescueth, and he worketh signs and wonders in heaven and in', 'Even pagan rulers can confess that earthly thrones fade before the eternal kingdom.', 4),
  ('daniel-nine-1', 'daniel-nine', 'SEVENTY WEEKS DETERMINED', 'Time decreed upon Daniel''s people and holy city in Gabriel''s message.', null, 'Daniel 9:24', 'the matter, and consider the vision. 24Seventy weeks are determined upon thy people and upon thy holy city, to finish the transgression, and to make an end of sins, and to make reconciliation for iniquity, and to bring in everlasting righteousness, and to sea', 'God marks out prophetic time for finishing transgression and bringing in everlasting righteousness.', 0),
  ('daniel-nine-2', 'daniel-nine', 'MESSIAH THE PRINCE', 'The Anointed One who appears after sixty-nine weeks in the prophecy.', null, 'Daniel 9:25', 'restore and to build Jerusalem unto the Messiah the Prince shall be seven weeks, and threescore and two weeks: the street shall be built again, and the wall, even in troublous times. 26And after threescore and two weeks shall Messiah be cut off, but not for hi', 'Christ''s first advent was foretold centuries before He entered Jerusalem.', 1),
  ('daniel-nine-3', 'daniel-nine', 'CUT OFF NOT FOR HIMSELF', 'Messiah is cut off in the middle of the seventieth week.', null, 'Daniel 9:26', 's. 26And after threescore and two weeks shall Messiah be cut off, but not for himself: and the people of the prince that shall come shall destroy the city and the sanctuary; and the end thereof shall be with a flood, and unto the end of the war desolations are', 'The cross was not accident but the fulfillment of heaven''s appointed timetable.', 2),
  ('daniel-nine-4', 'daniel-nine', 'CONFIRM COVENANT ONE WEEK', 'Messiah confirms the covenant during the final prophetic week.', null, 'Daniel 9:27', 'olations are determined. 27And he shall confirm the covenant with many for one week: and in the midst of the week he shall cause the sacrifice and the oblation to cease, and for the overspreading of abomina1660 Daniel 9', 'Christ''s ministry and sacrifice ratified the new covenant with humanity.', 3),
  ('daniel-nine-5', 'daniel-nine', 'ABOMINATION OF DESOLATION', 'Daniel links desolating abominations to the close of the seventy-weeks prophecy.', null, 'Daniel 9:27', 'ily sacrifice, and they shall place the abomination that maketh desolate. 1665 Daniel 11', 'False worship desolates what God consecrates — a warning repeated in later prophecy.', 4),
  ('daniel-ten-1', 'daniel-ten', 'MAN CLOTHED IN LINEN', 'A glorious figure girded with gold of Uphaz above the river.', null, 'Daniel 10:5', 's, and looked, and behold a certain man clothed in linen, whose loins were girded with fine gold of Uphaz: 6His body also was like the beryl, and his face as the appearance of lightning, and his eyes as lamps of fire, and his arms and his feet like in colour t', 'Heaven sends visible assurance that spiritual battles are fought under divine leadership.', 0),
  ('daniel-ten-2', 'daniel-ten', 'BODY LIKE BERYL', 'Part of the description of the man by the river Hiddekel.', null, 'Daniel 10:6', 's were girded with fine gold of Uphaz: 6His body also was like the beryl, and his face as the appearance of lightning, and his eyes as lamps of fire, and his arms and his feet like in colour to polished brass, and the voice of his words like the voice of a mul', 'Prophetic visions reveal the majesty of beings who serve the throne of God.', 1),
  ('daniel-ten-3', 'daniel-ten', 'PRINCE OF PERSIA', 'A spiritual power that withstood the angel twenty-one days.', null, 'Daniel 10:13', 'and I am come for thy words. 13But the prince of the kingdom of Persia withstood me one and twenty days: but, lo, Michael, one of the chief princes, came to help me; and I remained there with the kings of Persia. 14Now I am come to make thee understand what s', 'Behind earthly empires stand contending powers in the unseen war over nations.', 2),
  ('daniel-ten-4', 'daniel-ten', 'MICHAEL YOUR PRINCE', 'The chief prince who came to help against the kings of Persia.', null, 'Daniel 10:21', 'at holdeth with me in these things, but Michael your prince. 1663 Daniel 10', 'Michael stands for God''s people in heavenly conflict long before Daniel 12.', 3),
  ('daniel-ten-5', 'daniel-ten', 'STRENGTHENED FOR THE VISION', 'The man touched Daniel and told him to stand upright for the message.', null, 'Daniel 10:19', 'an, and he strengthened me, 19And said, O man greatly beloved, fear not: peace be unto thee, be strong, yea, be strong. And when he had spoken unto me, I was strengthened, and said, Let my lord speak; for thou hast strengthened me. 20Then said he, Knowest thou', 'God sustains His servants when revelations of end-time conflict overwhelm human strength.', 4)
insert into public.words (id, chapter_id, word, clue, expert_clue, verse, scripture, summary, sort_order) values
  ('exodus-sanctuary-1', 'exodus-sanctuary', 'PATTERN SHEWED THEE', 'Moses was commanded to build the tabernacle according to the heavenly model.', null, 'Exodus 25:9', 'anctuary; that I may dwell among them. 9According to all that I shew thee, after the pattern of the tabernacle, and the pattern of all the instruments thereof, even so shall ye make it. 10And they shall make an ark of shittim wood: two cubits and a half shall', 'The earthly sanctuary was a copy of the true tabernacle where Christ ministers.', 0),
  ('exodus-sanctuary-2', 'exodus-sanctuary', 'ARK OF THE TESTIMONY', 'The chest overlaid with gold holding the tables of the law.', null, 'Exodus 25:16', 'en the two cherubims which are upon the ark of the testimony, of all things which I will give thee in commandment unto the children of Israel. Exodus 25 179 Exodus 25', 'God''s law at the heart of the sanctuary reveals the standard of His government.', 1),
  ('exodus-sanctuary-3', 'exodus-sanctuary', 'MERCY SEAT OF GOLD', 'The lid where God promised to meet with Moses between the cherubim.', null, 'Exodus 25:17', 'hall give thee. 17And thou shalt make a mercy seat of pure gold: two cubits and a half shall be the length thereof, and a cubit and a half the breadth thereof. 18And thou shalt make two cherubims of gold, of beaten work shalt thou make them, in the two ends of', 'Mercy and law meet at the throne where intercession covers repentant sinners.', 2),
  ('exodus-sanctuary-4', 'exodus-sanctuary', 'CANDLESTICK OF PURE GOLD', 'Seven lamps giving light in the holy place.', null, 'Exodus 25:31', 'efore me alway. 31And thou shalt make a candlestick of pure gold: of beaten work shall the candlestick be made: his shaft, and his branches, his bowls, his knops, and his flowers, shall be of the same. 32And six branches shall come out of the sides of it; thre', 'The Spirit illuminates the church as the lampstand lit the first apartment.', 3),
  ('exodus-sanctuary-5', 'exodus-sanctuary', 'VEIL OF BLUE PURPLE', 'The curtain separating the holy from the most holy place.', null, 'Exodus 26:31', 'e in the mount. 31And thou shalt make a vail of blue, and purple, and scarlet, and fine twined linen of cunning work: with cherubims shall it be made: 32And thou shalt hang it upon four pillars of shittim wood overlaid with gold: their hooks shall be of gold,', 'Access to God''s presence was limited until Christ''s flesh was torn for us.', 4),
  ('leviticus-atonement-1', 'leviticus-atonement', 'DAY OF ATONEMENTS', 'The tenth day of the seventh month when the high priest made reconciliation.', null, 'Leviticus 16:29', 'of this seventh month there shall be a day of atonement: it shall be an holy convocation unto you; and ye shall afflict your souls, and offer an offering made by fire unto the Lord. 28And ye shall do no work in that same day: for it is a day of atonement, to', 'Typical services pointed forward to Christ''s final work removing sin from the record.', 0),
  ('leviticus-atonement-2', 'leviticus-atonement', 'TWO GOATS FOR SIN', 'Lots cast — one for the LORD and one for Azazel.', null, 'Leviticus 16:8', 'ron shall cast lots upon the two goats; one lot for the Lord, and the other lot for the scapegoat. 9And Aaron shall bring the goat upon which the Lord''S lot fell, and offer him for a sin offering. 10But the goat, on which the lot fell to be the scapegoat, shal', 'Sin is both atoned and removed — justice satisfied and guilt borne away.', 1),
  ('leviticus-atonement-3', 'leviticus-atonement', 'WITHIN THE VAIL', 'The high priest entered the most holy only on this day with blood.', null, 'Leviticus 16:15', 'ches, that thou mayest bring in thither within the vail the ark of the testimony: and the vail shall divide unto you between the holy place and the most holy. 34And thou shalt put the mercy seat upon the ark of the testimony in the most holy place. 35And thou', 'Only blood could open the inner sanctuary — fulfilled in Christ''s heavenly ministry.', 2),
  ('leviticus-atonement-4', 'leviticus-atonement', 'SCAPEGOAT BEAR SINS', 'The live goat sent into the wilderness bearing the confessed transgressions.', null, 'Leviticus 16:22', 'to the wilderness: 22And the goat shall bear upon him all their iniquities unto a land not inhabited: and he shall let go the goat in the wilderness. 23And Aaron shall come into the tabernacle of the congregation, and shall put off the linen garments, which he', 'Satan ultimately bears the final responsibility for sin''s origin and deception.', 3),
  ('leviticus-atonement-5', 'leviticus-atonement', 'AFFLICT YOUR SOULS', 'Israel was to humble themselves on the day of atonement.', null, 'Leviticus 16:31', 'on the tenth day of the month, ye shall afflict your souls, and do no work at all, whether it be one of your own country, or a stranger that sojourneth among you: 30For on that day shall the priest make an atonement for you, to cleanse you, that ye may be clea', 'Reconciliation with God requires heartfelt repentance, not mere ritual.', 4),
  ('hebrews-sanctuary-1', 'hebrews-sanctuary', 'HIGH PRIEST FOREVER', 'Melchisedec order — a priesthood that does not pass to another.', null, 'Hebrews 6:20', 'is for us entered, even Jesus, made an high priest for ever after the order of Melchisedec. Hebrews 6 2642 Hebrews 6', 'Jesus continues interceding because His priesthood never ends.', 0),
  ('hebrews-sanctuary-2', 'hebrews-sanctuary', 'MINISTER OF SANCTUARY', 'Christ serves in the true tabernacle which the Lord pitched.', null, 'Hebrews 8:2', 'hrone of the Majesty in the heavens; 2A minister of the sanctuary, and of the true tabernacle, which the Lord pitched, and not man. 3For every high priest is ordained to offer gifts and sacrifices: wherefore it is of necessity that this man have somewhat also', 'Heaven''s sanctuary is real — not metaphor but the center of salvation''s administration.', 1),
  ('hebrews-sanctuary-3', 'hebrews-sanctuary', 'BETTER COVENANT ESTABLISHED', 'The new covenant with better promises than the old.', null, 'Hebrews 8:6', 'nt ministry, by how much also he is the mediator of a better covenant, which was established upon better promises. 7For if that first covenant had been faultless, then should no place have been sought for the second. 8For finding fault with them, he saith, Beh', 'God writes His law on the heart under the covenant sealed by Christ''s blood.', 2),
  ('hebrews-sanctuary-4', 'hebrews-sanctuary', 'ONCE IN THE END', 'Christ appeared to put away sin by the sacrifice of Himself.', null, 'Hebrews 9:26', 'ce the foundation of the world: but now once in the end of the world hath he appeared to put away sin by the sacrifice of himself. 27And as it is appointed unto men once to die, but after this the judgment: 28So Christ was once offered to bear the sins of many', 'One perfect offering ended the need for repeated animal sacrifices.', 3),
  ('hebrews-sanctuary-5', 'hebrews-sanctuary', 'WITHOUT SIN UNTO SALVATION', 'Christ will appear the second time to those who look for Him.', null, 'Hebrews 9:28', 'for him shall he appear the second time without sin unto salvation. 2647 Hebrews 9', 'The same Saviour who died once will return for those waiting in faith.', 4),
  ('isaiah-comfort-1', 'isaiah-comfort', 'COMFORT YE MY PEOPLE', 'Heaven''s command to speak tenderly to Jerusalem.', null, 'Isaiah 40:1', 'Chapter 40 Comfort ye, comfort ye my people, saith your God. 2Speak ye comfortably to Jerusalem, and cry unto her, that her warfare is accomplished, that her iniquity is pardoned: for she hath received of the Lord''S hand double for', 'God''s message to the end-time church blends comfort with preparation.', 0),
  ('isaiah-comfort-2', 'isaiah-comfort', 'VOICE CRYING WILDERNESS', 'Prepare the way of the LORD — make straight a highway.', null, 'Isaiah 40:3', 'n of by the prophet Esaias, saying, The voice of one crying in the wilderness, Prepare ye the way of the Lord, make his paths straight. 4And the same John had his raiment of camel''s hair, and a leathern girdle about his loins; and his meat was locusts and wild', 'John the Baptist and end-time heralds call hearts to level every obstacle to Christ.', 1),
  ('isaiah-comfort-3', 'isaiah-comfort', 'ALL FLESH IS GRASS', 'Human glory fades but the word of our God stands forever.', null, 'Isaiah 40:6', 'id, Cry. And he said, What shall I cry? All flesh is grass, and all the goodliness thereof is as the flower of the field: 7The grass withereth, the flower fadeth: because the spirit of the Lord bloweth upon it: surely the people is grass. 8The grass withereth,', 'Prophetic study anchors the soul in what is eternal, not what withers.', 2),
  ('isaiah-comfort-4', 'isaiah-comfort', 'WORD OF GOD STAND FOREVER', 'Contrast to fading grass and flower of the field.', null, 'Isaiah 40:8', 's withereth, the flower fadeth: but the word of our God shall stand for ever. 9O Zion, that bringest good tidings, get thee up into the high mountain; O Jerusalem, that bringest good tidings, lift up thy voice with strength; lift it up, be not afraid; say unto', 'Scripture remains the unchanging foundation when cultures and empires pass.', 3),
  ('isaiah-comfort-5', 'isaiah-comfort', 'GIVE STRENGTH TO THE WEARY', 'They that wait upon the LORD renew their strength.', null, 'Isaiah 40:29', 'is no searching of his understanding. 29He giveth power to the faint; and to them that have no might he increaseth strength. 30Even the youths shall faint and be weary, and the young men shall utterly fall: 31But they that wait upon the Lord shall renew their', 'End-time endurance comes from waiting on God, not human enthusiasm.', 4),
  ('isaiah-servant-1', 'isaiah-servant', 'DESPISED AND REJECTED', 'The servant had no form nor comeliness that we should desire him.', null, 'Isaiah 53:3', 's no beauty that we should desire him. 3He is despised and rejected of men; a man of sorrows, and acquainted with grief: and we hid as it were our faces from him; he was despised, and we esteemed him not. 4Surely he hath borne our griefs, and carried our sorro', 'The world''s rejection of Christ reveals how sin blinds hearts to beauty.', 0),
  ('isaiah-servant-2', 'isaiah-servant', 'WOUNDED FOR TRANSGRESSIONS', 'He was bruised for our iniquities; chastisement brought us peace.', null, 'Isaiah 53:5', 'tten of God, and afflicted. 5But he was wounded for our transgressions, he was bruised for our iniquities: the chastisement of our peace was upon him; and with his stripes we are healed. 6All we like sheep have gone astray; we have turned every one to his own', 'Substitutionary suffering is the heart of the gospel and prophetic hope.', 1),
  ('isaiah-servant-3', 'isaiah-servant', 'LAID ON HIM INIQUITY', 'The LORD laid on Him the iniquity of us all.', null, 'Isaiah 53:6', 'y one to his own way; and the Lord hath laid on him the iniquity of us all. 7He was oppressed, and he was afflicted, yet he opened not his mouth: he is brought as a lamb to the slaughter, and as a sheep before her shearers is dumb, so he openeth not his mouth.', 'Christ bore collective guilt so repentant sinners might go free.', 2),
  ('isaiah-servant-4', 'isaiah-servant', 'OPENED NOT HIS MOUTH', 'As a lamb to slaughter, the servant was silent before shearers.', null, 'Isaiah 53:7', 'oppressed, and he was afflicted, yet he opened not his mouth: he is brought as a lamb to the slaughter, and as a sheep before her shearers is dumb, so he openeth not his mouth. 8He was taken from prison and from judgment: and who shall declare his generation?', 'Messiah''s silence at trial fulfilled prophecy and revealed perfect submission.', 3),
  ('isaiah-servant-5', 'isaiah-servant', 'MAKE INTERCESSION FOR TRANSGRESSORS', 'He bore sin of many and makes intercession for transgressors.', null, 'Isaiah 53:12', 'ssors; and he bare the sin of many, and made intercession for the transgressors. Isaiah 53 1393 Isaiah 53', 'The same priest who died still pleads for those who come to God through Him.', 4)
insert into public.words (id, chapter_id, word, clue, expert_clue, verse, scripture, summary, sort_order) values
  ('joel-prophecy-1', 'joel-prophecy', 'BLOW THE TRUMPET ZION', 'Alarm sounded in God''s holy mountain before the day of the LORD.', null, 'Joel 2:1', 'Chapter 2 Blow ye the trumpet in Zion, and sound an alarm in my holy mountain: let all the inhabitants of the land tremble: for the day of the Lord cometh, for it is nigh at hand; 2A day of darkness and of gloominess, a day of clo', 'Heaven calls the church to warn the world while mercy still lingers.', 0),
  ('joel-prophecy-2', 'joel-prophecy', 'DAY OF DARKNESS GLOOMINESS', 'Joel describes the day of the LORD as terrible and not to be desired.', null, 'Joel 2:2', 'Lord cometh, for it is nigh at hand; 2A day of darkness and of gloominess, a day of clouds and of thick darkness, as the morning spread upon the mountains: a great people and a strong; there hath not been ever the like, neither shall be any more after it, even', 'Prophetic language prepares believers for crisis without fostering fear without faith.', 1),
  ('joel-prophecy-3', 'joel-prophecy', 'POUR OUT MY SPIRIT', 'God will pour Spirit on all flesh — sons and daughters prophesy.', null, 'Joel 2:28', 'd it shall come to pass afterward, that I will pour out my spirit upon all flesh; and your sons and your daughters shall prophesy, your old men shall dream dreams, your young men shall see visions: 29And also upon the servants and upon the handmaids in those d', 'Pentecost and the latter rain share one promise — universal Spirit empowerment.', 2),
  ('joel-prophecy-4', 'joel-prophecy', 'SUN TURNED DARKNESS', 'Wonders in heaven and earth before the great and terrible day.', null, 'Joel 2:31', 'lood, and fire, and pillars of smoke. 31The sun shall be turned into darkness, and the moon into blood, before the great and the terrible day of the Lord come. 32And it shall come to pass, that whosoever shall call on the name of the Lord shall be delivered: f', 'Cosmic signs accompany both Pentecost-era fulfillment and final crisis.', 3),
  ('joel-prophecy-5', 'joel-prophecy', 'VALLEY OF DECISION', 'Multitudes gathered where the day of the LORD is near.', null, 'Joel 3:14', 'great. 14Multitudes, multitudes in the valley of decision: for the day of the Lord is near in the valley of decision. 15The sun and the moon shall be darkened, and the stars shall withdraw their shining. 16The Lord also shall roar out of Zion, and utter his v', 'Every soul eventually chooses sides in the great controversy between Christ and Satan.', 4),
  ('zechariah-temple-1', 'zechariah-temple', 'BRAND PLUCKED FROM FIRE', 'Israel pictured as a burning stick snatched from the flames.', null, 'Zechariah 3:2', 'en Jerusalem rebuke thee: is not this a brand plucked out of the fire? 3Now Joshua was clothed with filthy garments, and stood before the angel. 4And he answered and spake unto those that stood before him, saying, Take away the filthy garments from him. And un', 'God preserves a remnant despite their filthy garments and Satan''s accusations.', 0),
  ('zechariah-temple-2', 'zechariah-temple', 'CHANGE OF RAIMENT', 'Joshua stood before the angel with filthy garments removed.', null, 'Zechariah 3:4', 'from thee, and I will clothe thee with change of raiment. 5And I said, Let them set a fair mitre upon his head. So they set a fair mitre upon his head, and clothed him with garments. And the angel of the Lord stood by. 6And the angel of the Lord protested unt', 'Justification covers the believer with Christ''s righteousness in heavenly court.', 1),
  ('zechariah-temple-3', 'zechariah-temple', 'BEHOLD THE MAN BRANCH', 'The name of the Branch who shall build the temple of the LORD.', null, 'Zechariah 6:12', 'hus speaketh the Lord of hosts, saying, Behold the man whose name is The BRANCH; and he shall grow up out of his place, and he shall build the temple of the Lord: 13Even he shall build the temple of the Lord; and he shall bear the glory, and shall sit and rule', 'Christ builds a spiritual temple of living stones from every nation.', 2),
  ('zechariah-temple-4', 'zechariah-temple', 'NOT BY MIGHT NOR POWER', 'Zerubbabel shall finish the work by My Spirit, saith the LORD.', null, 'Zechariah 4:6', 'rd of the Lord unto Zerubbabel, saying, Not by might, nor by power, but by my spirit, saith the Lord of hosts. 7Who art thou, O great mountain? before Zerubbabel thou shalt become a plain: and he shall bring forth the headstone thereof with shoutings, crying,', 'Final gospel work succeeds through Spirit power, not human schemes.', 3),
  ('zechariah-temple-5', 'zechariah-temple', 'FLYING ROLL CURSE', 'The curse goes forth over the whole earth against thieves and false swearers.', null, 'Zechariah 5:3', 'up mine eyes, and looked, and behold a flying roll. 2And he said unto me, What seest thou? And I answered, I see a flying roll; the length thereof is twenty cubits, and the breadth thereof ten cubits. 3Then said he unto me, This is the curse that goeth forth', 'God''s law still bears witness against sin in every land before judgment falls.', 4),
  ('malachi-remnant-1', 'malachi-remnant', 'MESSENGER OF THE COVENANT', 'The Lord whom ye seek shall suddenly come to His temple.', null, 'Malachi 3:1', 'l suddenly come to his temple, even the messenger of the covenant, whom ye delight in: behold, he shall come, saith the Lord of hosts. 2But who may abide the day of his coming? and who shall stand when he appeareth? for he is like a refiner''s fire, and like fu', 'John prepared the way; Christ fulfilled the covenant promise at His first advent.', 0),
  ('malachi-remnant-2', 'malachi-remnant', 'REFINERS FIRE FULLERS SOAP', 'He shall sit as a refiner and purifier of the sons of Levi.', null, 'Malachi 3:2', 'and when he appeareth? for he is like a refiner''s fire, and like fullers'' sope: 3And he shall sit as a refiner and purifier of silver: and he shall purify the sons of Levi, and purge them as gold and silver, that they may offer unto the Lord an offering in rig', 'Preparation for the end purges character as fire purges metal.', 1),
  ('malachi-remnant-3', 'malachi-remnant', 'ROB GOD IN TITHES', 'Israel asked wherein they had robbed God — tithes and offerings.', null, 'Malachi 3:8', 'But ye said, Wherein shall we return? 8Will a man rob God? Yet ye have robbed me. But ye say, Wherein have we robbed thee? In tithes and offerings. 9Ye are cursed with a curse: for ye have robbed me, even this whole nation. 10Bring ye all the tithes into the', 'Stewardship reveals trust in God''s provision during the closing work.', 2),
  ('malachi-remnant-4', 'malachi-remnant', 'BOOK OF REMEMBRANCE', 'A book written for those who feared the LORD and thought upon His name.', null, 'Malachi 3:16', 'the Lord hearkened, and heard it, and a book of remembrance was written before him for them that feared the Lord, and that thought upon his name. 17And they shall be mine, saith the Lord of hosts, in that day when I make up my jewels; and I will spare them, as', 'Heaven records faithfulness that earth may forget or ridicule.', 3),
  ('malachi-remnant-5', 'malachi-remnant', 'SUN OF RIGHTEOUSNESS ARISE', 'With healing in His wings to those who fear God''s name.', null, 'Malachi 4:2', 'ut unto you that fear my name shall the Sun of righteousness arise with healing in his wings; and ye shall go forth, and grow up as calves of the stall. 3And ye shall tread down the wicked; for they shall be ashes under the soles of your feet in the day that I', 'The same day that burns the wicked brings healing to those who serve God.', 4),
  ('matthew-parables-1', 'matthew-parables', 'TEN VIRGINS WENT FORTH', 'They went to meet the bridegroom — five wise and five foolish.', null, 'Matthew 25:1', 'l the kingdom of heaven be likened unto ten virgins, which took their lamps, and went forth to meet the bridegroom. 2And five of them were wise, and five were foolish. 3They that were foolish took their lamps, and took no oil with them: 4But the wise took oil', 'Outward profession without inner oil fails when the cry sounds at midnight.', 0),
  ('matthew-parables-2', 'matthew-parables', 'MIDNIGHT CRY BEHOLD BRIDEGROOM', 'The shout that roused the sleeping virgins to trim their lamps.', null, 'Matthew 25:6', 'ied, they all slumbered and slept. 6And at midnight there was a cry made, Behold, the bridegroom cometh; go ye out to meet him. 7Then all those virgins arose, and trimmed their lamps. 8And the foolish said unto the wise, Give us of your oil; for our lamps are', 'Sudden awakening precedes Christ''s return — preparation cannot be borrowed at the last moment.', 1),
  ('matthew-parables-3', 'matthew-parables', 'I WAS AN HUNGERED', 'The King judges nations by treatment of the least of His brethren.', null, 'Matthew 25:35', 'from the foundation of the world: 35For I was an hungred, and ye gave me meat: I was thirsty, and ye gave me drink: I was a stranger, and ye took me in: 36Naked, and ye clothed me: I was sick, and ye visited me: I was in prison, and ye came unto me. 37Then sha', 'Practical compassion toward God''s people marks those ready for the kingdom.', 2),
  ('matthew-parables-4', 'matthew-parables', 'DEPART FROM ME YE CURSED', 'Those on the left hear sentence into everlasting fire prepared for devil and angels.', null, 'Matthew 25:41', 'he say also unto them on the left hand, Depart from me, ye cursed, into everlasting fire, prepared for the devil and his angels: 42For I was an hungred, and ye gave me no meat: I was thirsty, and ye gave me no drink: 43I was a stranger, and ye took me not in:', 'Final separation is real — character fixed in relation to Christ and His people.', 3),
  ('matthew-parables-5', 'matthew-parables', 'ENTER THOU GOOD SERVANT', 'The faithful servant invited into the joy of the lord.', null, 'Matthew 25:21', 'will make thee ruler over many things: enter thou into the joy of thy lord. 22He also that had received two talents came and said, Lord, thou deliveredst unto me two talents: behold, I have gained two other talents beside them. 23His lord said unto him, Well', 'Stewardship of gifts now determines participation in eternal joy.', 4),
  ('luke-watchfulness-1', 'luke-watchfulness', 'FIG TREE PUTTETH FORTH', 'When leaves appear, summer is near — so know the kingdom is nigh.', null, 'Luke 21:29', 'nigh. 29And he spake to them a parable; Behold the fig tree, and all the trees; 30When they now shoot forth, ye see and know of your own selves that summer is now nigh at hand. 31So likewise ye, when ye see these things come to pass, know ye that the kingdom o', 'Signs in prophecy are meant to inspire watchfulness, not date-setting pride.', 0),
  ('luke-watchfulness-2', 'luke-watchfulness', 'THIS GENERATION NOT PASS', 'Heaven and earth shall pass but Christ''s words stand forever.', null, 'Luke 21:32', 'nigh at hand. 32Verily I say unto you, This generation shall not pass away, till all be fulfilled. 33Heaven and earth shall pass away: but my words shall not pass away. 34And take heed to yourselves, lest at any time your hearts be overcharged with surfeiting', 'Prophetic word is sure even when centuries unfold before fulfillment.', 1),
  ('luke-watchfulness-3', 'luke-watchfulness', 'TAKE HEED TO YOURSELVES', 'Lest hearts be overcharged with surfeiting and cares of this life.', null, 'Luke 21:34', 'but my words shall not pass away. 34And take heed to yourselves, lest at any time your hearts be overcharged with surfeiting, and drunkenness, and cares of this life, and so that day come upon you unawares. 35For as a snare shall it come on all them that dwell', 'Spiritual drowsiness is the danger of the last days as much as open sin.', 2),
  ('luke-watchfulness-4', 'luke-watchfulness', 'WATCH THEREFORE AND PRAY', 'Command to be counted worthy to escape and stand before the Son of man.', null, 'Luke 21:36', 'dwell on the face of the whole earth. 36Watch ye therefore, and pray always, that ye may be accounted worthy to escape all these things that shall come to pass, and to stand before the Son of man. 37And in the day time he was teaching in the temple; and at nig', 'Prayer keeps the soul alert for the unexpected hour of the Advent.', 3),
  ('luke-watchfulness-5', 'luke-watchfulness', 'REDEMPTION DRAWETH NIGH', 'When these things begin to come to pass, look up.', null, 'Luke 21:28', 'en look up, and lift up your heads; for your redemption draweth nigh. 29And he spake to them a parable; Behold the fig tree, and all the trees; 30When they now shoot forth, ye see and know of your own selves that summer is now nigh at hand. 31So likewise ye, w', 'Crisis for the world is hope for those whose citizenship is in heaven.', 4)
insert into public.words (id, chapter_id, word, clue, expert_clue, verse, scripture, summary, sort_order) values
  ('acts-restoration-1', 'acts-restoration', 'SOUND FROM HEAVEN', 'Rushing mighty wind filled the house where disciples waited.', null, 'Acts 2:2', 'all with one accord in one place. 2And suddenly there came a sound from heaven as of a rushing mighty wind, and it filled all the house where they were sitting. 3And there appeared unto them cloven tongues like as of fire, and it sat upon each of them. 4And t', 'The early rain began with audible heaven-sent power, not human organization.', 0),
  ('acts-restoration-2', 'acts-restoration', 'CLOVEN TONGUES LIKE FIRE', 'Sat upon each of them when the Spirit was poured out.', null, 'Acts 2:3', 'sitting. 3And there appeared unto them cloven tongues like as of fire, and it sat upon each of them. 4And they were all filled with the Holy Ghost, and began to speak with other tongues, as the Spirit gave them utterance. 5And there were dwelling at Jerusalem', 'Fire symbolizes purification and proclamation accompanying Spirit baptism.', 1),
  ('acts-restoration-3', 'acts-restoration', 'TIMES OF RESTITUTION', 'Peter said heaven must receive Christ until all things restored.', null, 'Acts 3:21', '1Whom the heaven must receive until the times of restitution of all things, which God hath spoken by the mouth of all his holy prophets since the world began. 22For Moses truly said unto the fathers, A prophet shall the Lord your God raise up unto you of your', 'History moves toward restoration of Eden''s order through Christ''s reign.', 2),
  ('acts-restoration-4', 'acts-restoration', 'PROPHET LIKE UNTO ME', 'Moses'' prophecy of a Prophet the people must hear.', null, 'Acts 3:22', '2For Moses truly said unto the fathers, A prophet shall the Lord your God raise up unto you of your brethren, like unto me; him shall ye hear in all things whatsoever he shall say unto you. 23And it shall come to pass, that every soul, which will not hear that', 'Christ fulfills Moses'' prediction — rejecting Him repeats Israel''s fatal error.', 3),
  ('acts-restoration-5', 'acts-restoration', 'REPENT AND BE CONVERTED', 'Peter''s call that sins may be blotted out when refreshing comes.', null, 'Acts 3:19', 'should suffer, he hath so fulfilled. 19Repent ye therefore, and be converted, that your sins may be blotted out, when the times of refreshing shall come from the presence of the Lord; 20And he shall send Jesus Christ, which before was preached unto you: Acts', 'Revival precedes latter rain — conversion opens the door to Spirit refreshing.', 4),
  ('romans-gospel-1', 'romans-gospel', 'NOT ASHAMED OF GOSPEL', 'Paul''s theme — power of God unto salvation to every believer.', null, 'Romans 1:16', 'pel to you that are at Rome also. 16For I am not ashamed of the gospel of Christ: for it is the power of God unto salvation to every one that believeth; to the Jew first, and also to the Greek. 17For therein is the righteousness of God revealed from faith to f', 'End-time witnesses proclaim the same gospel Paul defended in Rome.', 0),
  ('romans-gospel-2', 'romans-gospel', 'REVEALED FROM FAITH', 'The just shall live by faith — righteousness of God revealed.', null, 'Romans 1:17', 'from faith to faith: as it is written, The just shall live by faith. 18For the wrath of God is revealed from heaven against all ungodliness and unrighteousness of men, who hold the truth in unrighteousness; 19Because that which may be known of God is manifest', 'Habakkuk''s motto became the Reformation and remains the remnant''s foundation.', 1),
  ('romans-gospel-3', 'romans-gospel', 'ALL HAVE SINNED', 'Universal need of grace — none righteous, no not one.', null, 'Romans 3:23', 'ieve: for there is no difference: 23For all have sinned, and come short of the glory of God; 24Being justified freely by his grace through the redemption that is in Christ Jesus: Romans 3 2488 Romans 3', 'Judgment truth begins with honest confession of universal sinfulness.', 2),
  ('romans-gospel-4', 'romans-gospel', 'WAGES OF SIN DEATH', 'But gift of God is eternal life through Jesus Christ.', null, 'Romans 6:23', '23For the wages of sin is death; but the gift of God is eternal life through Jesus Christ our Lord. 2495 Romans 6', 'Two destinies — earned death or gifted life through Christ.', 3),
  ('romans-gospel-5', 'romans-gospel', 'CREATION GROANING TRAVAILETH', 'Whole creation waits for manifestation of sons of God.', null, 'Romans 8:22', 'the children of God. 22For we know that the whole creation groaneth and travaileth in pain together until now. 23And not only they, but ourselves also, which have the firstfruits of the Spirit, even we ourselves groan within ourselves, waiting for the adoption', 'Nature itself testifies that this world is bound for liberation at the Advent.', 4),
  ('first-corinthians-resurrection-1', 'first-corinthians-resurrection', 'LAST TRUMP SHALL SOUND', 'Dead raised incorruptible when trumpet sounds at end.', null, '1 Corinthians 15:52', 'kling of an eye, at the last trump: for the trumpet shall sound, and the dead shall be raised incorruptible, and we shall be changed. 53For this corruptible must put on incorruption, and this mortal must put on immortality. 54So when this corruptible shall hav', 'Paul links resurrection hope to the same trumpet imagery used in Revelation.', 0),
  ('first-corinthians-resurrection-2', 'first-corinthians-resurrection', 'VICTORY THROUGH LORD', 'Thanks be to God who giveth us victory through Jesus Christ.', null, '1 Corinthians 15:57', 'd the strength of sin is the law. 57But thanks be to God, which giveth us the victory through our Lord Jesus Christ. 58Therefore, my beloved brethren, be ye stedfast, unmovable, always abounding in the work of the Lord, forasmuch as ye know that your labour is', 'Resurrection is not wishful thinking but guaranteed triumph through Christ.', 1),
  ('first-corinthians-resurrection-3', 'first-corinthians-resurrection', 'STUMBLING BLOCK TO JEWS', 'Preaching Christ crucified — foolishness to Greeks, power to believers.', null, '1 Corinthians 1:23', 'eeks seek after wisdom: 23But we preach Christ crucified, unto the Jews a stumblingblock, and unto the Greeks foolishness; 24But unto them which are called, both Jews and Greeks, Christ the power of God, and the wisdom of God. 25Because the foolishness of God', 'The cross remains the dividing line between human wisdom and saving power.', 2),
  ('first-corinthians-resurrection-4', 'first-corinthians-resurrection', 'SHEW YOU MYSTERY', 'We shall not all sleep but be changed in a moment.', null, '1 Corinthians 15:51', 'ruption inherit incorruption. 51Behold, I shew you a mystery; We shall not all sleep, but we shall all be changed, 52In a moment, in the twinkling of an eye, at the last trump: for the trumpet shall sound, and the dead shall be raised incorruptible, and we sha', 'Living saints experience translation — a distinct end-time promise.', 3),
  ('first-corinthians-resurrection-5', 'first-corinthians-resurrection', 'CORRUPTIBLE PUT ON INCORRUPTION', 'Mortal must put on immortality when victory swallows death.', null, '1 Corinthians 15:53', 'le, and we shall be changed. 53For this corruptible must put on incorruption, and this mortal must put on immortality. 54So when this corruptible shall have put on incorruption, and this mortal shall have put on immortality, then shall be brought to pass the s', 'Glorified bodies complete salvation at the last day.', 4),
  ('ephesians-armour-1', 'ephesians-armour', 'WRESTLE NOT AGAINST FLESH', 'Our struggle is against principalities and spiritual wickedness in high places.', null, 'Ephesians 6:12', 'd against the wiles of the devil. 12For we wrestle not against flesh and blood, but against principalities, against powers, against the rulers of the darkness of this world, against spiritual wickedness in high places. 13Wherefore take unto you the whole armou', 'Prophetic conflict is ultimately spiritual, though it plays out in history.', 0),
  ('ephesians-armour-2', 'ephesians-armour', 'GIRDLE OF TRUTH', 'First piece of armour — stand therefore having truth about the loins.', null, 'Ephesians 6:14', 'done all, to stand. 14Stand therefore, having your loins girt about with truth, and having on the breastplate of righteousness; 15And your feet shod with the preparation of the gospel of peace; 16Above all, taking the shield of faith, wherewith ye shall be ab', 'Doctrinal integrity holds every other piece of Christian armor in place.', 1),
  ('ephesians-armour-3', 'ephesians-armour', 'SHIELD OF FAITH', 'Quenches all the fiery darts of the wicked one.', null, 'Ephesians 6:16', 'ospel of peace; 16Above all, taking the shield of faith, wherewith ye shall be able to quench all the fiery darts of the wicked. 17And take the helmet of salvation, and the sword of the Spirit, which is the word of God: 18Praying always with all prayer and sup', 'Trust in God''s word extinguishes Satan''s accusations and temptations.', 2),
  ('ephesians-armour-4', 'ephesians-armour', 'HELMET OF SALVATION', 'Protects the mind in the battle for the soul.', null, 'Ephesians 6:17', 'll the fiery darts of the wicked. 17And take the helmet of salvation, and the sword of the Spirit, which is the word of God: 18Praying always with all prayer and supplication in the Spirit, and watching thereunto with all perseverance and supplication for all', 'Assurance of salvation guards against despair in the time of trouble.', 3),
  ('ephesians-armour-5', 'ephesians-armour', 'SWORD OF THE SPIRIT', 'The word of God — only offensive weapon listed.', null, 'Ephesians 6:17', 'd take the helmet of salvation, and the sword of the Spirit, which is the word of God: 18Praying always with all prayer and supplication in the Spirit, and watching thereunto with all perseverance and supplication for all saints; 19And for me, that utterance m', 'Scripture is both shield and weapon in the great controversy.', 4),
  ('thessalonians-coming-1', 'thessalonians-coming', 'COMFORT ONE ANOTHER', 'Words about those asleep — sorrow not as others without hope.', null, '1 Thessalonians 4:18', 'l we ever be with the Lord. 18Wherefore comfort one another with these words. 1 Thessalonians 4 2606 1 Thessalonians 4', 'Advent hope transforms grief into anticipation for reunited saints.', 0),
  ('thessalonians-coming-2', 'thessalonians-coming', 'THIEF IN THE NIGHT', 'Day of the Lord comes when peace and safety are declared.', null, '1 Thessalonians 5:2', 'ou. 2For yourselves know perfectly that the day of the Lord so cometh as a thief in the night. 3For when they shall say, Peace and safety; then sudden destruction cometh upon them, as travail upon a woman with child; and they shall not escape. 4But ye, brethre', 'Suddenness catches the unprepared; watchfulness marks the faithful.', 1),
  ('thessalonians-coming-3', 'thessalonians-coming', 'MAN OF SIN REVEALED', 'Son of perdition exalts himself above all that is called God.', null, '2 Thessalonians 2:3', 'pt there come a falling away first, and that man of sin be revealed, the son of perdition; 4Who opposeth and exalteth himself above all that is called God, or that is worshipped; so that he as God sitteth in the temple of God, shewing himself that he is God. 5', 'Paul foresaw a developing apostasy before Christ''s return.', 2),
  ('thessalonians-coming-4', 'thessalonians-coming', 'WHAT WITHHOLDETH NOW', 'Something restrains until the wicked one is taken out of the way.', null, '2 Thessalonians 2:7', 'ery of iniquity doth already work: only he who now letteth will let, until he be taken out of the way. 8And then shall that Wicked be revealed, whom the Lord shall consume with the spirit of his mouth, and shall destroy with the brightness of his coming: 9Even', 'Prophetic timing involves restraining forces removed before final deception.', 3),
  ('thessalonians-coming-5', 'thessalonians-coming', 'STAND FAST HOLD TRADITIONS', 'Paul urges steadfastness in taught word whether by epistle or speech.', null, '2 Thessalonians 2:15', 'rd Jesus Christ. 15Therefore, brethren, stand fast, and hold the traditions which ye have been taught, whether by word, or our epistle. 16Now our Lord Jesus Christ himself, and God, even our Father, which hath loved us, and hath given us everlasting consolatio', 'End-time stability comes from holding apostolic teaching, not novel theories.', 4)
insert into public.words (id, chapter_id, word, clue, expert_clue, verse, scripture, summary, sort_order) values
  ('second-peter-day-1', 'second-peter-day', 'SCOFFERS WALKING AFTER LUST', 'Mockers ask where is promise of His coming since fathers fell asleep.', null, '2 Peter 3:3', 'and Saviour: 3Knowing this first, that there shall come in the last days scoffers, walking after their own lusts, 4And saying, Where is the promise of his coming? for since the fathers fell asleep, all things continue as they were from the beginning of the cr', 'Skepticism about the Advent is itself a sign of the last days.', 0),
  ('second-peter-day-2', 'second-peter-day', 'ONE DAY IS AS THOUSAND', 'Lord not slack — a day with Him is as a thousand years.', null, '2 Peter 3:8', 'be not ignorant of this one thing, that one day is with the Lord as a thousand years, and a thousand years as one day. 9The Lord is not slack concerning his promise, as some men count slackness; but is longsuffering to us-ward, not willing that any should peri', 'Apparent delay is patience, not broken promise.', 1),
  ('second-peter-day-3', 'second-peter-day', 'ELEMENTS MELT FERVENT HEAT', 'Heavens pass away with great noise at day of God.', null, '2 Peter 3:10', 'l pass away with a great noise, and the elements shall melt with fervent heat, the earth also and the works that are therein shall be burned up. 11Seeing then that all these things shall be dissolved, what manner of persons ought ye to be in all holy conversat', 'Earth''s purification by fire precedes the new creation.', 2),
  ('second-peter-day-4', 'second-peter-day', 'NEW HEAVENS NEW EARTH', 'Peter promises dwelling wherein dwelleth righteousness after fire.', null, '2 Peter 3:13', 'we, according to his promise, look for new heavens and a new earth, wherein dwelleth righteousness. 14Wherefore, beloved, seeing that ye look for such things, be diligent that ye may be found of him in peace, without spot, and blameless. 15And account that th', 'Peter''s hope matches Revelation''s — righteousness fills remade creation.', 3),
  ('second-peter-day-5', 'second-peter-day', 'GROW IN GRACE KNOWLEDGE', 'Final exhortation while waiting for day of God.', null, '2 Peter 3:18', '18But grow in grace, and in the knowledge of our Lord and Saviour Jesus Christ. To him be glory both now and for ever. Amen. 2680 2 Peter 3', 'Waiting time is growth time — not idle speculation.', 4),
  ('rev-throne-1', 'rev-throne', 'THRONE SET IN HEAVEN', 'John saw one sitting on the throne with emerald rainbow round about.', null, 'Revelation 4:2', 'ately I was in the spirit: and, behold, a throne was set in heaven, and one sat on the throne. 3And he that sat was to look upon like a jasper and a sardine stone: and there was a rainbow round about the throne, in sight like unto an emerald. 4And round about', 'History''s conflicts unfold before a occupied throne — God still reigns.', 0),
  ('rev-throne-2', 'rev-throne', 'FOUR AND TWENTY ELDERS', 'They cast crowns before the throne and worship Him that lives forever.', null, 'Revelation 4:10', 'twenty seats: and upon the seats I saw four and twenty elders sitting, clothed in white raiment; and they had on their heads crowns of gold. 5And out of the throne proceeded lightnings and thunderings and voices: and there were seven lamps of fire burning bef', 'Redeemed representatives join heaven''s council worshipping the Creator.', 1),
  ('rev-throne-3', 'rev-throne', 'FOUR BEASTS FULL OF EYES', 'Each unlike the other — lion, calf, man, flying eagle.', null, 'Revelation 4:6', 'hrone, and round about the throne, were four beasts full of eyes before and behind. 7And the first beast was like a lion, and the second beast like a calf, and the third beast had a face as a man, and the fourth beast was like a flying eagle. 8And the four bea', 'Heaven''s intelligence covers earth with vigilant praise day and night.', 2),
  ('rev-throne-4', 'rev-throne', 'HOLY HOLY HOLY LORD', 'Beasts rest not saying Holy, holy, holy, Lord God Almighty.', null, 'Revelation 4:8', 'nd they rest not day and night, saying, Holy, holy, holy, Lord God Almighty, which was, and is, and is to come. 9And when those beasts give glory and honour and thanks to him that sat on the throne, who liveth for ever and ever, 10The four and twenty elders fa', 'Isaiah''s sanctuary cry fills heaven — holiness is the atmosphere of God''s court.', 3),
  ('rev-throne-5', 'rev-throne', 'THOU ART WORTHY CREATOR', 'Worthy art thou to receive glory for thou hast created all things.', null, 'Revelation 4:11', 'eir crowns before the throne, saying, 11Thou art worthy, O Lord, to receive glory and honour and power: for thou hast created all things, and for thy pleasure they are and were created. Revelation 4 2704 Revelation 4', 'Creation worship anchors end-time message against evolution and secularism.', 4),
  ('rev-144000-1', 'rev-144000', 'SEALED IN FOREHEADS', 'Angels hold back winds until servants sealed in foreheads.', null, 'Revelation 7:3', 'er the sea, nor the trees, till we have sealed the servants of our God in their foreheads. 4And I heard the number of them which were sealed: and there were sealed an hundred and forty and four thousand of all the tribes of the children of Israel. 5Of the trib', 'Sealing is intellectual and spiritual loyalty fixed before final plagues.', 0),
  ('rev-144000-2', 'rev-144000', 'HURT NOT EARTH SEA', 'Four angels restrained until sealing complete.', null, 'Revelation 7:3', 'to hurt the earth and the sea, 3Saying, Hurt not the earth, neither the sea, nor the trees, till we have sealed the servants of our God in their foreheads. 4And I heard the number of them which were sealed: and there were sealed an hundred and forty and four t', 'Mercy''s bounds remain until God''s people are prepared.', 1),
  ('rev-144000-3', 'rev-144000', 'NUMBERED ONE HUNDRED FORTY FOUR', 'Multitude sealed — symbolic completeness from Israel''s tribes.', null, 'Revelation 7:4', 'hich were sealed: and there were sealed an hundred and forty and four thousand of all the tribes of the children of Israel. 5Of the tribe of Juda were sealed twelve thousand. Of the tribe of Reuben were sealed twelve thousand. Of the tribe of Gad were sealed t', 'The remnant represents perfect spiritual Israel, not ethnic limitation.', 2),
  ('rev-144000-4', 'rev-144000', 'GREAT MULTITUDE NO MAN NUMBER', 'White-robed multitude from all nations before the throne.', null, 'Revelation 7:9', 'housand. 9After this I beheld, and, lo, a great multitude, which no man could number, of all nations, and kindreds, and people, and tongues, stood before the throne, and before the Lamb, clothed with white robes, and palms in their hands; 10And cried with a lo', 'Beyond the symbolic 144,000 stands an innumerable harvest of saved.', 3),
  ('rev-144000-5', 'rev-144000', 'WASHED ROBES IN BLOOD', 'They came out of great tribulation and washed robes white.', null, 'Revelation 7:14', 'came out of great tribulation, and have washed their robes, and made them white in the blood of the Lamb. 15Therefore are they before the throne of God, and serve him day and night in his temple: and he that sitteth on the throne shall dwell among them. 16They', 'Tribulation saints reach glory through Lamb''s blood, not human merit.', 4),
  ('rev-witnesses-1', 'rev-witnesses', 'TWO WITNESSES PROPHESY', 'They prophesy twelve hundred sixty days clothed in sackcloth.', null, 'Revelation 11:3', 'two months. 3And I will give power unto my two witnesses, and they shall prophesy a thousand two hundred and threescore days, clothed in sackcloth. 4These are the two olive trees, and the two candlesticks standing before the God of the earth. 5And if any man w', 'Scripture and Spirit testify through prophetic periods of oppression.', 0),
  ('rev-witnesses-2', 'rev-witnesses', 'TWO OLIVE TREES', 'Standing before the God of the whole earth.', null, 'Revelation 11:4', 's, clothed in sackcloth. 4These are the two olive trees, and the two candlesticks standing before the God of the earth. 5And if any man will hurt them, fire proceedeth out of their mouth, and devoureth their enemies: and if any man will hurt them, he must in t', 'Zechariah''s imagery links oil of Spirit with lamp of word.', 1),
  ('rev-witnesses-3', 'rev-witnesses', 'FIRE PROCEED OUT MOUTH', 'Witnesses devour enemies with fire from their mouths.', null, 'Revelation 11:5', 'earth. 5And if any man will hurt them, fire proceedeth out of their mouth, and devoureth their enemies: and if any man will hurt them, he must in this manner be killed. 6These have power to shut heaven, that it rain not in the days of their prophecy: and have', 'God''s word through witnesses consumes opposition as Jeremiah foretold.', 2),
  ('rev-witnesses-4', 'rev-witnesses', 'DEAD BODIES THREE DAYS', 'Beast kills witnesses; bodies lie in street of great city.', null, 'Revelation 11:8', 'vercome them, and kill them. 8And their dead bodies shall lie in the street of the great city, which spiritually is called Sodom and Egypt, where also our Lord was crucified. 9And they of the people and kindreds and tongues and nations shall see their dead bod', 'Temporary suppression of testimony precedes dramatic vindication.', 3),
  ('rev-witnesses-5', 'rev-witnesses', 'SPIRIT OF LIFE FROM GOD', 'Breath enters witnesses; great fear falls on beholders.', null, 'Revelation 11:11', '11And after three days and an half the Spirit of life from God entered into them, and they stood upon their feet; and great fear fell upon them which saw them. 12And they heard a great voice from heaven saying unto them, Come up hither. And they ascended up t', 'Revived testimony after apparent defeat marks latter rain power.', 4),
  ('rev-woman-dragon-1', 'rev-woman-dragon', 'GREAT RED DRAGON', 'Seven heads and ten horns — old serpent called Devil and Satan.', null, 'Revelation 12:3', 'ed another wonder in heaven; and behold a great red dragon, having seven heads and ten horns, and seven crowns upon his heads. 4And his tail drew the third part of the stars of heaven, and did cast them to the earth: and the dragon stood before the woman which', 'Behind earthly persecution stands the dragon who hates the woman''s seed.', 0),
  ('rev-woman-dragon-2', 'rev-woman-dragon', 'MICHAEL FOUGHT DRAGON', 'War in heaven; dragon cast out with his angels.', null, 'Revelation 12:7', 'ore days. 7And there was war in heaven: Michael and his angels fought against the dragon; and the dragon fought and his angels, 8And prevailed not; neither was their place found any more in heaven. 9And the great dragon was cast out, that old serpent, called t', 'Cosmic conflict intensifies as probation nears its close.', 1),
  ('rev-woman-dragon-3', 'rev-woman-dragon', 'ACCUSER OF BRETHREN', 'Devil cast down who accused them before God day and night.', null, 'Revelation 12:10', 'ser of our brethren is cast down, which accused them before our God day and night. 11And they overcame him by the blood of the Lamb, and by the word of their testimony; and they loved not their lives unto the death. 12Therefore rejoice, ye heavens, and ye that', 'Nearness of Advent means Satan''s accusations increase but are overcome by the Lamb.', 2),
  ('rev-woman-dragon-4', 'rev-woman-dragon', 'WILDERNESS PREPARED WOMAN', 'Woman fled where she is nourished twelve hundred sixty days.', null, 'Revelation 12:6', 'is throne. 6And the woman fled into the wilderness, where she hath a place prepared of God, that they should feed her there a thousand two hundred and threescore days. 7And there was war in heaven: Michael and his angels fought against the dragon; and the drag', 'God sustains the church through prophetic periods of hiding and persecution.', 3),
  ('rev-woman-dragon-5', 'rev-woman-dragon', 'EARTH OPENED MOUTH', 'Earth helped woman and swallowed flood from dragon''s mouth.', null, 'Revelation 12:16', '. 16And the earth helped the woman, and the earth opened her mouth, and swallowed up the flood which the dragon cast out of his mouth. Revelation 12 2715 Revelation 12', 'Providence shields the remnant when human and demonic forces combine.', 4)
insert into public.words (id, chapter_id, word, clue, expert_clue, verse, scripture, summary, sort_order) values
  ('rev-harvest-1', 'rev-harvest', 'EVERLASTING GOSPEL PREACH', 'Angel with gospel to every nation, kindred, tongue, and people.', null, 'Revelation 14:6', 'fly in the midst of heaven, having the everlasting gospel to preach unto them that dwell on the earth, and to every nation, and kindred, and tongue, and people, 7Saying with a loud voice, Fear God, and give glory to him; for the hour of his judgment is come:', 'First angel''s message is gospel-centered, not merely judgment.', 0),
  ('rev-harvest-2', 'rev-harvest', 'FALL DOWN WORSHIP HIM', 'Fear God and give glory — for hour of judgment is come.', null, 'Revelation 14:7', 'and people, 7Saying with a loud voice, Fear God, and give glory to him; for the hour of his judgment is come: and worship him that made heaven, and earth, and the sea, and the fountains of waters. 8And there followed another angel, saying, Babylon is fallen,', 'Creator worship is the answer to evolutionary and spiritualistic deception.', 1),
  ('rev-harvest-3', 'rev-harvest', 'PATIENCE OF SAINTS', 'Here are they that keep commandments and faith of Jesus.', null, 'Revelation 14:12', 'oever receiveth the mark of his name. 12Here is the patience of the saints: here are they that keep the commandments of God, and the faith of Jesus. 13And I heard a voice from heaven saying unto me, Write, Blessed are the dead which die in the Lord from hencef', 'Remnant identity combines law and gospel — commandments and Jesus'' faith.', 2),
  ('rev-harvest-4', 'rev-harvest', 'ONE LIKE SON OF MAN', 'Sitting on white cloud with golden crown and sharp sickle.', null, 'Revelation 14:14', 'I looked, and behold a white cloud, and upon the cloud one sat like unto the Son of man, having on his head a golden crown, and in his hand a sharp sickle. 15And another angel came out of the temple, crying with a loud voice to him that sat on the cloud, Thrus', 'Harvest imagery points to closing work separating wheat from tares.', 3),
  ('rev-harvest-5', 'rev-harvest', 'WINEPRESS TRODDEN WITHOUT', 'Blood to horses'' bridles for thousand six hundred furlongs.', null, 'Revelation 14:20', 'inepress of the wrath of God. 20And the winepress was trodden without the city, and blood came out of the winepress, even unto the horse bridles, by the space of a thousand and six hundred furlongs. 2720 Revelation 14', 'Judgment on oppressors follows gospel rejection.', 4),
  ('rev-plagues-1', 'rev-plagues', 'SEVEN GOLDEN VIALS', 'Seven angels with seven plagues — last plagues filled with wrath of God.', null, 'Revelation 15:7', 'four beasts gave unto the seven angels seven golden vials full of the wrath of God, who liveth for ever and ever. 8And the temple was filled with smoke from the glory of God, and from his power; and no man was able to enter into the temple, till the seven pla', 'Final judgments fall without mixture of mercy on hardened rebels.', 0),
  ('rev-plagues-2', 'rev-plagues', 'NOISOME GRIEVOUS SORE', 'First vial upon men which had mark of beast and worshipped image.', null, 'Revelation 16:2', 's vial upon the earth; and there fell a noisome and grievous sore upon the men which had the mark of the beast, and upon them which worshipped his image. 3And the second angel poured out his vial upon the sea; and it became as the blood of a dead man: and ever', 'Plagues target allegiance to the beast system, not random suffering.', 1),
  ('rev-plagues-3', 'rev-plagues', 'POURED OUT HIS VIAL UPON SEA', 'Second angel turns sea to blood as of a dead man.', null, 'Revelation 16:3', 'hipped his image. 3And the second angel poured out his vial upon the sea; and it became as the blood of a dead man: and every living soul died in the sea. 4And the third angel poured out his vial upon the rivers and fountains of waters; and they became blood.', 'Creation itself bears witness against rebellion in the plague era.', 2),
  ('rev-plagues-4', 'rev-plagues', 'EUPHRATES DRIED UP', 'Sixth vial prepares way for kings of the east.', null, 'Revelation 16:12', 'oured out his vial upon the great river Euphrates; and the water thereof was dried up, that the way of the kings of the east might be prepared. 13And I saw three unclean spirits like frogs come out of the mouth of the dragon, and out of the mouth of the beast,', 'Prophetic geography symbolizes removal of barriers before final gathering.', 3),
  ('rev-plagues-5', 'rev-plagues', 'IT IS DONE', 'Great voice from throne declares completion when seventh vial poured.', null, 'Revelation 16:17', 'lled in the Hebrew tongue Armageddon. 17And the seventh angel poured out his vial into the air; and there came a great voice out of the temple of heaven, from the throne, saying, It is done. 18And there were voices, and thunders, and lightnings; and there was', 'Heaven announces the end of mercy''s mixed cup — probation closed.', 4),
  ('rev-harlot-1', 'rev-harlot', 'MYSTERY BABYLON GREAT', 'Woman on scarlet beast full of names of blasphemy.', null, 'Revelation 17:5', 'd upon her forehead was a name written, MYSTERY, BABYLON THE GREAT, THE MOTHER OF HARLOTS AND ABOMINATIONS OF THE EARTH. 6And I saw the woman drunken with the blood of the saints, and with the blood of the martyrs of Jesus: and when I saw her, I wondered with', 'Religious apostasy rides political power in end-time coalition.', 0),
  ('rev-harlot-2', 'rev-harlot', 'DRUNK WITH BLOOD SAINTS', 'Harlot drunken with blood of martyrs of Jesus.', null, 'Revelation 17:6', 'IONS OF THE EARTH. 6And I saw the woman drunken with the blood of the saints, and with the blood of the martyrs of Jesus: and when I saw her, I wondered with great admiration. 7And the angel said unto me, Wherefore didst thou marvel? I will tell thee the myste', 'Persecution history identifies systems hostile to commandment keepers.', 1),
  ('rev-harlot-3', 'rev-harlot', 'TEN HORNS UPON BEAST', 'Horns hate harlot and make her desolate and naked.', null, 'Revelation 17:16', 'itudes, and nations, and tongues. 16And the ten horns which thou sawest upon the beast, these shall hate the whore, and shall make her desolate and naked, and shall eat her flesh, and burn her with fire. Revelation 17 2724 Revelation 17', 'Earthly allies eventually turn on ecclesiastical Babylon.', 2),
  ('rev-harlot-4', 'rev-harlot', 'MIGHTY ANGEL CRIED', 'Babylon the great is fallen, is fallen — before second angel''s echo.', null, 'Revelation 18:2', 'd mightily with a strong voice, saying, Babylon the great is fallen, is fallen, and is become the habitation of devils, and the hold of every foul spirit, and a cage of every unclean and hateful bird. 3For all nations have drunk of the wine of the wrath of her', 'Moral fall precedes political collapse of confused religious systems.', 3),
  ('rev-harlot-5', 'rev-harlot', 'THY MERCHANDISE OF GOLD', 'Kings of earth mourn when Babylon''s commerce ceases in one hour.', null, 'Revelation 18:12', 'an buyeth their merchandise any more: 12The merchandise of gold, and silver, and precious stones, and of pearls, and fine linen, and purple, and silk, and scarlet, and all thyine wood, and all manner vessels of ivory, and all manner vessels of most precious wo', 'Economic entanglement with Babylon makes separation costly but necessary.', 4),
  ('rev-victory-1', 'rev-victory', 'FAITHFUL AND TRUE RIDER', 'Heaven opens — rider on white horse called Faithful and True.', null, 'Revelation 19:11', 'ite horse; and he that sat upon him was called Faithful and True, and in righteousness he doth judge and make war. 12His eyes were as a flame of fire, and on his head were many crowns; and he had a name written, that no man knew, but he himself. 13And he was c', 'Christ returns as warrior-king, not secret rapture thief only.', 0),
  ('rev-victory-2', 'rev-victory', 'ARMIES IN HEAVEN FOLLOW', 'Armies on white horses clothed in fine linen follow the Word of God.', null, 'Revelation 19:14', 's name is called The Word of God. 14And the armies which were in heaven followed him upon white horses, clothed in fine linen, white and clean. 15And out of his mouth goeth a sharp sword, that with it he should smite the nations: and he shall rule them with a', 'Saints join the final campaign as glorified companions of Christ.', 1),
  ('rev-victory-3', 'rev-victory', 'MARRIAGE OF LAMB COME', 'Wife made herself ready — fine linen is righteousness of saints.', null, 'Revelation 19:7', 'nd rejoice, and give honour to him: for the marriage of the Lamb is come, and his wife hath made herself ready. 8And to her was granted that she should be arrayed in fine linen, clean and white: for the fine linen is the righteousness of saints. 9And he saith', 'Corporate readiness of church precedes eternal union with Bridegroom.', 2),
  ('rev-victory-4', 'rev-victory', 'LAKE OF FIRE BURNING', 'Beast and false prophet cast alive into lake of fire.', null, 'Revelation 19:20', 't worshipped his image. These both were cast alive into a lake of fire burning with brimstone. 21And the remnant were slain with the sword of him that sat upon the horse, which sword proceeded out of his mouth: and all the fowls were filled with their flesh. 2', 'Judgment on leaders of rebellion precedes broader final destruction.', 3),
  ('rev-victory-5', 'rev-victory', 'DEVIL CAST INTO LAKE', 'After millennium, devil cast into lake where beast and false prophet are.', null, 'Revelation 20:10', 'of heaven, and devoured them. 10And the devil that deceived them was cast into the lake of fire and brimstone, where the beast and the false prophet are, and shall be tormented day and night for ever and ever. 11And I saw a great white throne, and him that sat', 'Sin problem ends when author of deception is destroyed forever.', 4),
  ('rev-new-creation-1', 'rev-new-creation', 'TABERNACLE OF GOD WITH MEN', 'God shall dwell with them — they shall be His people.', null, 'Revelation 21:3', 'voice out of heaven saying, Behold, the tabernacle of God is with men, and he will dwell with them, and they shall be his people, and God himself shall be with them, and be their God. 4And God shall wipe away all tears from their eyes; and there shall be no mo', 'Eden lost becomes Eden restored with God living among redeemed.', 0),
  ('rev-new-creation-2', 'rev-new-creation', 'ALPHA AND OMEGA BEGINNING', 'He that sat on throne — I am Alpha and Omega, the beginning and the end.', null, 'Revelation 21:6', 'll wail because of him. Even so, Amen. 8I am Alpha and Omega, the beginning and the ending, saith the Lord, which is, and which was, and which is to come, the Almighty. 9I John, who also am your brother, and companion in tribulation, and in the kingdom and pat', 'Christ who started creation completes it in the new earth.', 1),
  ('rev-new-creation-3', 'rev-new-creation', 'RIVER OF WATER OF LIFE', 'Clear as crystal proceeding from throne of God and of the Lamb.', null, 'Revelation 22:1', 'Chapter 22 And he shewed me a pure river of water of life, clear as crystal, proceeding out of the throne of God and of the Lamb. 2In the midst of the street of it, and on either side of the river, was there the tree of life, which bare twelve manner', 'Eternal life flows from the throne — no separation from source.', 2),
  ('rev-new-creation-4', 'rev-new-creation', 'TREE OF LIFE FRUIT', 'Leaves for healing of nations on either side of the river.', null, 'Revelation 22:2', 'either side of the river, was there the tree of life, which bare twelve manner of fruits, and yielded her fruit every month: and the leaves of the tree were for the healing of the nations. 3And there shall be no more curse: but the throne of God and of the Lam', 'Access forbidden at Eden''s fall is restored for eternity.', 3),
  ('rev-new-creation-5', 'rev-new-creation', 'SPIRIT AND BRIDE SAY COME', 'Let him that heareth say Come — whosoever will take water of life freely.', null, 'Revelation 22:17', 'and the bright and morning star. 17And the Spirit and the bride say, Come. And let him that heareth say, Come. And let him that is athirst come. And whosoever will, let him take the water of life freely. 18For I testify unto every man that heareth the words o', 'Even at Scripture''s close, gospel invitation remains open until probation ends.', 4)
